function convert(s: string, numRows: number): string {
  if (numRows === 1 || numRows >= s.length) return s;
  const rows: string[] = Array.from({ length: numRows }, () => "");
  let cur = 0, dir = -1;
  for (const c of s) {
    rows[cur] += c;
    if (cur === 0 || cur === numRows - 1) dir = -dir;
    cur += dir;
  }
  return rows.join("");
}
